import{_ as a,o as n,c as i,a2 as p}from"./chunks/framework.C24VBsJ9.js";const b=JSON.parse('{"title":"引脚复用与 GPIO 硬件原理","description":"","frontmatter":{"title":"引脚复用与 GPIO 硬件原理"},"headers":[],"relativePath":"tutorial/driver/02_pinctrl_gpio/02_hardware_foundation.md","filePath":"tutorial/driver/02_pinctrl_gpio/02_hardware_foundation.md","lastUpdated":1781369075000}'),l={name:"tutorial/driver/02_pinctrl_gpio/02_hardware_foundation.md"};function e(r,s,t,h,k,d){return n(),i("div",null,[...s[0]||(s[0]=[p(`<h1 id="i-mx-6ull-引脚复用与-gpio-硬件原理" tabindex="-1">i.MX 6ULL 引脚复用与 GPIO 硬件原理 <a class="header-anchor" href="#i-mx-6ull-引脚复用与-gpio-硬件原理" aria-label="Permalink to &quot;i.MX 6ULL 引脚复用与 GPIO 硬件原理&quot;">​</a></h1><h2 id="前言-先搞清楚我们在操作什么" tabindex="-1">前言：先搞清楚我们在操作什么 <a class="header-anchor" href="#前言-先搞清楚我们在操作什么" aria-label="Permalink to &quot;前言：先搞清楚我们在操作什么&quot;">​</a></h2><p>说实话，在深入子系统源码之前，我觉得非常有必要先搞清楚硬件是怎么工作的。很多教程一上来就讲 pinctrl 驱动、讲 gpio_chip，结果读者对硬件完全没有概念，看着那些抽象的数据结构完全不知道它们在映射什么硬件功能。</p><p>这就像你学开车，教练直接给你讲发动机原理、悬挂系统，但你连方向盘和油门在哪都不知道。所以我们的策略是：先搞清楚硬件长什么样，再来看软件是怎么抽象它的。</p><h2 id="引脚复用-一个物理引脚-多种功能" tabindex="-1">引脚复用：一个物理引脚，多种功能 <a class="header-anchor" href="#引脚复用-一个物理引脚-多种功能" aria-label="Permalink to &quot;引脚复用：一个物理引脚，多种功能&quot;">​</a></h2><p>让我们先来回答一个问题：为什么需要引脚复用？</p><p>i.MX 6ULL 这个芯片有很强大的功能——UART、SPI、I2C、PWM、Ethernet 等等。但如果每个功能都配独立的物理引脚，芯片的封装会变得非常大，成本也会飙升。所以芯片厂商做了一个很聪明的决定：让一个物理引脚可以被多个功能模块共享。</p><p>这就是**引脚复用（Pin Multiplexing）**的概念。</p><p>你想象一下，你家的客厅有&quot;多种用途&quot;：平时是客厅，有客人来了可以当客房，过年的时候还能当餐厅。同一个物理空间，在不同的场景下有不同的功能。芯片的引脚也是这样，GPIO1_IO03 这个引脚可以被配置成 GPIO，也可以被配置成 I2C1_SDA，还可以配置成 UART1_DCE_RX，等等。</p><p>具体选哪个功能，由我们通过软件来配置。配置的入口就是 IOMUXC（I/O Multiplexer Controller）控制器。</p><h3 id="iomuxc-控制器" tabindex="-1">IOMUXC 控制器 <a class="header-anchor" href="#iomuxc-控制器" aria-label="Permalink to &quot;IOMUXC 控制器&quot;">​</a></h3><p>IOMUXC 是 i.MX 系列芯片里专门负责引脚复用的硬件模块。你可以把它理解成一个&quot;巨大的多路选择器&quot;，每个引脚都有一个开关，决定这个引脚的信号连接到哪个内部功能模块。</p><p>在芯片手册里，你会看到每个引脚都有一个 MUX 寄存器。这个寄存器决定了引脚的功能模式。比如 GPIO1_IO03 的 MUX 寄存器（SW_MUX_CTL_PAD_GPIO1_IO03）：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>位 [2:0] - MUX_MODE</span></span>
<span class="line"><span>          000 = ALT0 - 这个引脚作为某个功能模块的信号</span></span>
<span class="line"><span>          001 = ALT1 - 这个引脚作为另一个功能模块的信号</span></span>
<span class="line"><span>          ...</span></span>
<span class="line"><span>          101 = ALT5 = GPIO - 这个引脚作为 GPIO 使用</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>当我们写 <code>writel(0x5, MUX_CTL_GPIO1_IO03)</code> 的时候，实际上是在告诉 IOMUXC：把 GPIO1_IO03 这个引脚连接到 GPIO 模块，而不是连接到 UART、I2C 或者其他模块。</p><h3 id="引脚的多种功能" tabindex="-1">引脚的多种功能 <a class="header-anchor" href="#引脚的多种功能" aria-label="Permalink to &quot;引脚的多种功能&quot;">​</a></h3><p>让我给你看一个真实的例子。GPIO1_IO03 这个引脚在 i.MX 6ULL 里有 9 种功能模式：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MUX_MODE = 0: I2C1_SDA      (I2C1 的数据线)</span></span>
<span class="line"><span>MUX_MODE = 1: GPT1_COMPARE3 (定时器比较输出)</span></span>
<span class="line"><span>MUX_MODE = 2: USB_OTG2_OC   (USB 过流检测)</span></span>
<span class="line"><span>MUX_MODE = 3: OSC32K_32K_OUT (32kHz 时钟输出)</span></span>
<span class="line"><span>MUX_MODE = 4: USDHC1_CD_B   (SD 卡检测)</span></span>
<span class="line"><span>MUX_MODE = 5: GPIO1_IO03    (GPIO 模式) ← 我们要用的</span></span>
<span class="line"><span>MUX_MODE = 6: CCM_DI0_EXT_CLK (外部时钟输入)</span></span>
<span class="line"><span>MUX_MODE = 7: SRC_TESTER_ACK (测试信号)</span></span>
<span class="line"><span>MUX_MODE = 8: UART1_DCE_RX  (UART1 接收)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>这些信息都定义在设备树的 pinfunc.h 文件里：</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#define</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MX6UL_PAD_GPIO1_IO03__I2C1_SDA</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">       0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0068</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">02f4</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">05a8</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#define</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MX6UL_PAD_GPIO1_IO03__GPT1_COMPARE3</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0068</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">02f4</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#define</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MX6UL_PAD_GPIO1_IO03__USB_OTG2_OC</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0068</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">02f4</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0660</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#define</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MX6UL_PAD_GPIO1_IO03__OSC32K_32K_OUT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0068</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">02f4</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#define</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MX6UL_PAD_GPIO1_IO03__USDHC1_CD_B</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0068</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">02f4</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0668</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#define</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MX6UL_PAD_GPIO1_IO03__GPIO1_IO03</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">     0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0068</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">02f4</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ← 这一行</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#define</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MX6UL_PAD_GPIO1_IO03__CCM_DI0_EXT_CLK</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0068</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">02f4</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#define</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MX6UL_PAD_GPIO1_IO03__SRC_TESTER_ACK</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0068</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">02f4</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0000</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 7</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#define</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MX6UL_PAD_GPIO1_IO03__UART1_DCE_RX</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">   0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0068</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">02f4</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0624</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>这里每个宏定义有 5 个参数（后面会详细解释），第 4 个参数就是 MUX_MODE 的值。你可以看到 <code>MX6UL_PAD_GPIO1_IO03__GPIO1_IO03</code> 的第 4 个参数是 5，对应的就是 ALT5 模式。</p><h2 id="pad-配置-不只是选择功能" tabindex="-1">PAD 配置：不只是选择功能 <a class="header-anchor" href="#pad-配置-不只是选择功能" aria-label="Permalink to &quot;PAD 配置：不只是选择功能&quot;">​</a></h2><p>选择了功能之后还没完，引脚的电气特性也需要配置。这就像是装修房子，你决定了客厅的用途，还得决定铺什么地板、装什么灯、墙面刷什么颜色。</p><p>这些电气特性包括：驱动强度、上下拉电阻、迟滞、速率等等。它们会影响信号的质量和抗干扰能力。</p><h3 id="pad-寄存器" tabindex="-1">PAD 寄存器 <a class="header-anchor" href="#pad-寄存器" aria-label="Permalink to &quot;PAD 寄存器&quot;">​</a></h3><p>每个引脚除了有 MUX 寄存器，还有一个 PAD 寄存器（SW_PAD_CTL_PAD_GPIO1_IO03）。这个寄存器配置引脚的电气特性。</p><p>i.MX 6ULL 的 PAD 寄存器是 32 位的，每个位都有特定的含义：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>位 [16]    - HYS   (迟滞使能)</span></span>
<span class="line"><span>位 [15:14] - PUS   (上下拉选择)</span></span>
<span class="line"><span>             00 = 100K 下拉</span></span>
<span class="line"><span>             01 = 47K 上拉</span></span>
<span class="line"><span>             10 = 100K 上拉</span></span>
<span class="line"><span>             11 = 22K 上拉</span></span>
<span class="line"><span>位 [13]    - PUE   (上下拉使能)</span></span>
<span class="line"><span>             0 = 保留 / 100K 下拉</span></span>
<span class="line"><span>             1 = 上拉/下拉使能</span></span>
<span class="line"><span>位 [12]    - PKE   (保持使能)</span></span>
<span class="line"><span>             0 = 禁用保持器</span></span>
<span class="line"><span>             1 = 使能保持器</span></span>
<span class="line"><span>位 [11]    - ODE   (开漏使能)</span></span>
<span class="line"><span>             0 = 禁止开漏</span></span>
<span class="line"><span>             1 = 使能开漏</span></span>
<span class="line"><span>位 [10:6]  - SPEED (速率选择)</span></span>
<span class="line"><span>             000 = 低速</span></span>
<span class="line"><span>             001 = 中速</span></span>
<span class="line"><span>             010 = 高速</span></span>
<span class="line"><span>             100 = 超高速</span></span>
<span class="line"><span>位 [5:3]   - DSE   (驱动强度选择)</span></span>
<span class="line"><span>             000 = 关闭驱动</span></span>
<span class="line"><span>             001 = R0(260 欧姆)</span></span>
<span class="line"><span>             010 = R0/2</span></span>
<span class="line"><span>             011 = R0/3</span></span>
<span class="line"><span>             100 = R0/4</span></span>
<span class="line"><span>             101 = R0/5</span></span>
<span class="line"><span>             110 = R0/6</span></span>
<span class="line"><span>             111 = R0/7</span></span>
<span class="line"><span>位 [1:0]   - SRE  (快速 slew rate)</span></span>
<span class="line"><span>             0 = 慢速 slew rate</span></span>
<span class="line"><span>             1 = 快速 slew rate</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br></div></div><p>这些参数的具体含义取决于你的应用场景。比如：</p><ul><li><strong>驱动强度（DSE）</strong>：如果你的引脚要驱动长线或者多个负载，就需要更大的驱动强度。</li><li><strong>上下拉（PUS/PUE/PKE）</strong>：如果引脚在空闲时可能悬空，就需要加上拉或下拉电阻来避免不确定状态。</li><li><strong>迟滞（HYS）</strong>：对于输入引脚，使能迟滞可以提高抗干扰能力。</li><li><strong>速率（SPEED/SRE）</strong>：对于高速信号（如 UART、SPI），需要配置更快的速率。</li></ul><p>我们的 LED 驱动使用的配置值是 <code>0x10B0</code>，让我们来分解一下：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0x10B0 = 0b0001 0000 1011 0000</span></span>
<span class="line"><span></span></span>
<span class="line"><span>位 [16]    HYS   = 0  (不使能迟滞)</span></span>
<span class="line"><span>位 [15:14] PUS   = 10 (100K 上拉)</span></span>
<span class="line"><span>位 [13]    PUE   = 1  (使能上拉)</span></span>
<span class="line"><span>位 [12]    PKE   = 1  (使能保持器)</span></span>
<span class="line"><span>位 [11]    ODE   = 0  (禁止开漏)</span></span>
<span class="line"><span>位 [10:6]  SPEED = 00010 (中速)</span></span>
<span class="line"><span>位 [5:3]   DSE   = 011 (R0/3)</span></span>
<span class="line"><span>位 [1:0]   SRE   = 0  (慢速 slew rate)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>这个配置对于 LED 控制来说完全足够。LED 不需要高速信号，也不需要很强的驱动能力，所以用了中速和中等驱动强度。</p><h2 id="gpio-模块-点亮-led-的最后一步" tabindex="-1">GPIO 模块：点亮 LED 的最后一步 <a class="header-anchor" href="#gpio-模块-点亮-led-的最后一步" aria-label="Permalink to &quot;GPIO 模块：点亮 LED 的最后一步&quot;">​</a></h2><p>当我们把引脚配置成 GPIO 功能之后，还需要配置 GPIO 模块本身才能控制 LED。</p><p>i.MX 6ULL 有多个 GPIO 模块（GPIO1~GPIO5），每个模块最多控制 32 个 GPIO。GPIO1_IO03 表示这是 GPIO1 模块的第 3 号引脚。</p><h3 id="gpio-寄存器" tabindex="-1">GPIO 寄存器 <a class="header-anchor" href="#gpio-寄存器" aria-label="Permalink to &quot;GPIO 寄存器&quot;">​</a></h3><p>GPIO 模块有一组寄存器，最常用的有几个：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DR (Data Register)      - 数据寄存器，读写 GPIO 的值</span></span>
<span class="line"><span>GDIR (Direction Register) - 方向寄存器，设置 GPIO 是输入还是输出</span></span>
<span class="line"><span>PSR (Pad Status Register) - 状态寄存器，读取 GPIO 的实际电平</span></span>
<span class="line"><span>ICR1/ICR2 (Interrupt Control) - 中断控制寄存器</span></span>
<span class="line"><span>IMR (Interrupt Mask)    - 中断屏蔽寄存器</span></span>
<span class="line"><span>ISR (Interrupt Status)  - 中断状态寄存器</span></span>
<span class="line"><span>EDGE_SEL (Edge Select)  - 边沿选择寄存器</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>对于我们的 LED 控制，只需要关注 DR 和 GDIR 这两个寄存器。</p><h4 id="gdir-方向寄存器" tabindex="-1">GDIR：方向寄存器 <a class="header-anchor" href="#gdir-方向寄存器" aria-label="Permalink to &quot;GDIR：方向寄存器&quot;">​</a></h4><p>在使用 GPIO 之前，必须先设置它的方向：是输入还是输出。</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 设置 GPIO1_IO03 为输出</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">writel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">readl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(GPIO1_GDIR) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), GPIO1_GDIR);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>GDIR 寄存器的每一位对应一个 GPIO。位 3 对应 GPIO1_IO03，写 1 表示输出，写 0 表示输入。</p><h4 id="dr-数据寄存器" tabindex="-1">DR：数据寄存器 <a class="header-anchor" href="#dr-数据寄存器" aria-label="Permalink to &quot;DR：数据寄存器&quot;">​</a></h4><p>对于输出引脚，写 DR 寄存器可以设置引脚的电平。</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 点亮 LED（写 0）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">writel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">readl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(GPIO1_DR) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ~</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), GPIO1_DR);</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 熄灭 LED（写 1）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">writel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">readl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(GPIO1_DR) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), GPIO1_DR);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>对于输入引脚，读 DR 寄存器可以获取引脚的电平。</p><h2 id="时钟控制-别忘了给-gpio-模块供电" tabindex="-1">时钟控制：别忘了给 GPIO 模块供电 <a class="header-anchor" href="#时钟控制-别忘了给-gpio-模块供电" aria-label="Permalink to &quot;时钟控制：别忘了给 GPIO 模块供电&quot;">​</a></h2><p>这里有个很容易被忽略的细节：GPIO 模块也需要时钟！如果时钟没使能，你操作 GPIO 寄存器不会有任何效果。</p><p>i.MX 6ULL 的时钟由 CCM（Clock Controller Module）控制。每个外设模块都有对应的时钟门控寄存器，需要手动使能。</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 使能 GPIO1 的时钟</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// CCM_CCGR1 的位 [27:26] 控制 GPIO1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">writel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">readl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(IMX6U_CCM_CCGR1) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 26</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">), IMX6U_CCM_CCGR1);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>CCM_CCGRx 寄存器每个模块占 2 位：</p><ul><li><code>00</code> = 时钟关闭（低功耗模式）</li><li><code>01</code> = 时钟在运行模式下开启</li><li><code>10</code> = 保留</li><li><code>11</code> = 时钟始终开启</li></ul><p>⚠️ <strong>注意</strong>：这一步真的很容易忘！如果你配置了引脚、设置了方向，但 LED 就是不亮，大概率是时钟没使能。</p><h2 id="完整的初始化流程" tabindex="-1">完整的初始化流程 <a class="header-anchor" href="#完整的初始化流程" aria-label="Permalink to &quot;完整的初始化流程&quot;">​</a></h2><p>现在让我们把所有步骤串起来，看看完整的初始化流程是什么样子的：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 使能 GPIO1 模块的时钟</span></span>
<span class="line"><span>   writel(readl(CCM_CCGR1) | (3 &lt;&lt; 26), CCM_CCGR1);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 配置 GPIO1_IO03 的引脚复用为 GPIO 功能</span></span>
<span class="line"><span>   writel(0x5, MUX_CTL_PAD_GPIO1_IO03);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 配置 GPIO1_IO03 的电气特性</span></span>
<span class="line"><span>   writel(0x10B0, PAD_CTL_PAD_GPIO1_IO03);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 设置 GPIO1_IO03 为输出模式</span></span>
<span class="line"><span>   writel(readl(GPIO1_GDIR) | (1 &lt;&lt; 3), GPIO1_GDIR);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 控制 GPIO1_IO03 的电平</span></span>
<span class="line"><span>   writel(readl(GPIO1_DR) &amp; ~(1 &lt;&lt; 3), GPIO1_DR);  // 点亮</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p>每一步都必须按顺序来，不能跳过。而且每一步都有对应的寄存器地址，你需要从芯片手册里查到这些地址。</p><h2 id="硬件连接-低电平有效" tabindex="-1">硬件连接：低电平有效 <a class="header-anchor" href="#硬件连接-低电平有效" aria-label="Permalink to &quot;硬件连接：低电平有效&quot;">​</a></h2><p>最后让我们看看硬件连接。我们的 LED 是连接在 GPIO1_IO03 上的，但有一个细节：这个 LED 是<strong>低电平有效</strong>的。</p><p>什么叫低电平有效？意思是当 GPIO 输出低电平（0V）的时候，LED 点亮；当 GPIO 输出高电平（3.3V）的时候，LED 熄灭。</p><p>这是因为 LED 的接法。常见的有两种接法：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>高电平有效：</span></span>
<span class="line"><span>3.3V → [限流电阻] → [LED] → GPIO</span></span>
<span class="line"><span></span></span>
<span class="line"><span>低电平有效：</span></span>
<span class="line"><span>3.3V → [限流电阻] → [LED] → GPIO</span></span>
<span class="line"><span>                    ↓</span></span>
<span class="line"><span>                  (实际上 LED 的负极接 GPIO)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>低电平有效的接法更常见，因为很多芯片的 GPIO 灌电流能力（sink capability）比拉电流能力（source capability）更强。</p><p>所以在我们的驱动代码里，你会发现：</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// LED 初始化时设置为 1（熄灭）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gpio_direction_output</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(led.gpio_sub_sys_nr, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 点亮 LED 时写 0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gpio_set_value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(led.gpio_sub_sys_nr, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 熄灭 LED 时写 1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gpio_set_value</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(led.gpio_sub_sys_nr, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>这个逻辑看起来是反的，但配合硬件连接就是对的。</p><p>如果你在设备树里看到 <code>GPIO_ACTIVE_LOW</code>，就是在告诉内核：这个 GPIO 是低电平有效的。内核会自动处理反转，你就可以用正常的逻辑（1 表示开，0 表示关）来编程了。</p><h2 id="寄存器地址一览" tabindex="-1">寄存器地址一览 <a class="header-anchor" href="#寄存器地址一览" aria-label="Permalink to &quot;寄存器地址一览&quot;">​</a></h2><p>为了方便你查阅，我把涉及到的寄存器地址列出来：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 时钟控制</span></span>
<span class="line"><span>CCM_CCGR1    = 0x020C406C</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// GPIO1 模块</span></span>
<span class="line"><span>GPIO1_DR     = 0x0209C000  // 数据寄存器</span></span>
<span class="line"><span>GPIO1_GDIR   = 0x0209C004  // 方向寄存器</span></span>
<span class="line"><span>GPIO1_PSR    = 0x0209C008  // 状态寄存器</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// GPIO1_IO03 的引脚控制</span></span>
<span class="line"><span>MUX_CTL_PAD_GPIO1_IO03    = 0x020E0068  // 引脚复用控制</span></span>
<span class="line"><span>PAD_CTL_PAD_GPIO1_IO03    = 0x020E02F4  // 电气特性配置</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>这些地址可以从 i.MX 6ULL 的参考手册（Reference Manual）里查到。手册有几千页，但你需要关注的只是 GPIO 章节和 IOMUXC 章节。</p><h2 id="下一章-软件登场" tabindex="-1">下一章：软件登场 <a class="header-anchor" href="#下一章-软件登场" aria-label="Permalink to &quot;下一章：软件登场&quot;">​</a></h2><p>现在我们对硬件有了完整的理解。我们知道了：</p><ol><li>引脚可以通过 IOMUXC 配置成不同的功能</li><li>引脚的电气特性可以通过 PAD 寄存器配置</li><li>GPIO 模块需要时钟使能才能工作</li><li>GPIO 的方向和数据需要通过 GDIR 和 DR 寄存器控制</li></ol><p>接下来就是有趣的部分了：Linux 内核是怎么把这些硬件操作抽象成子系统的？pinctrl 子系统和 gpio 子系统是如何协同工作的？</p><p><strong>下一步：</strong> 阅读 <a href="./03_pinctrl_subsystem_arch">03_pinctrl_subsystem_arch.md</a> 了解 pinctrl 子系统的架构和实现。</p>`,78)])])}const u=a(l,[["render",e]]);export{b as __pageData,u as default};
